import json,re,os,glob
from collections import defaultdict

chap_dir='blueprint/src/chapters'
# 1. Parse blueprint blocks: label, lean, file, existing uses (statement+proof merged), block char span
blocks={}  # label -> dict
label2file={}
for f in sorted(glob.glob(chap_dir+'/*.tex')):
    base=os.path.basename(f)[:-4]
    txt=open(f).read()
    # find environments with \label
    for m in re.finditer(r'\\begin\{(theorem|lemma|definition|proposition|corollary)\}(.*?)\\end\{\1\}',txt,re.S):
        body=m.group(2)
        lm=re.search(r'\\label\{([^}]+)\}',body)
        if not lm: continue
        label=lm.group(1)
        leanm=re.search(r'\\lean\{([^}]+)\}',body)
        lean=leanm.group(1).strip() if leanm else None
        uses=set()
        for um in re.finditer(r'\\uses\{([^}]*)\}',body):
            for u in um.group(1).split(','):
                u=u.strip()
                if u: uses.add(u)
        label2file[label]=base
        blocks[label]={'file':base,'lean':lean,'stmt_uses':uses}
# also capture proof \uses that follow (proofs are separate envs)
# parse proof environments and attach uses to nearest preceding label via \proves or sequence
# Simpler: for each file, also scan proof envs uses and attach to last label seen
for f in sorted(glob.glob(chap_dir+'/*.tex')):
    base=os.path.basename(f)[:-4]
    txt=open(f).read()
    # iterate over all envs in order
    last_label=None
    for m in re.finditer(r'\\begin\{(theorem|lemma|definition|proposition|corollary|proof)\}(.*?)\\end\{\1\}',txt,re.S):
        env=m.group(1); body=m.group(2)
        if env=='proof':
            pm=re.search(r'\\proves\{([^}]+)\}',body)
            tgt=pm.group(1).strip() if pm else last_label
            if tgt and tgt in blocks:
                for um in re.finditer(r'\\uses\{([^}]*)\}',body):
                    for u in um.group(1).split(','):
                        u=u.strip()
                        if u: blocks[tgt]['stmt_uses'].add(u)
        else:
            lm=re.search(r'\\label\{([^}]+)\}',body)
            if lm: last_label=lm.group(1)

lean2label={}
for l,d in blocks.items():
    if d['lean']: lean2label[d['lean']]=l

# 2. Locate each lean decl in .lean sources, extract body span
lean_files=glob.glob('AlgebraicJacobian/**/*.lean',recursive=True)+glob.glob('AlgebraicJacobian.lean')
# Build a list of (start_idx, lean_name, file, text) for declarations
# We'll find for each known lean_name its definition site
decl_sites={}  # lean_name -> (file, start, end)
file_txt={}
# gather all decl start positions per file
decl_re=re.compile(r'^\s*(?:@\[[^\]]*\]\s*)*(?:noncomputable\s+|private\s+|protected\s+|scoped\s+|local\s+)*(?:theorem|lemma|def|instance|abbrev|structure|class|inductive)\s+([A-Za-z0-9_\'\.]+)',re.M)
for f in lean_files:
    txt=open(f).read(); file_txt[f]=txt
    starts=[(m.start(),m.group(1)) for m in decl_re.finditer(txt)]
    for i,(pos,name) in enumerate(starts):
        end=starts[i+1][0] if i+1<len(starts) else len(txt)
        # store by simple name; need full name match later
        decl_sites.setdefault(name,[]).append((f,pos,end))

# map full lean_name -> body. Lean names are namespaced; the decl_re captures the local name after keyword.
# Build namespace tracking per file to reconstruct full names.
def full_names(f):
    txt=file_txt[f]
    res=[]  # (fullname, start, end)
    ns_stack=[]
    # tokenize lines
    lines=txt.split('\n'); idx=0
    # We need char offsets; track
    offsets=[]; c=0
    for ln in lines:
        offsets.append(c); c+=len(ln)+1
    open_secvar=[]
    for li,ln in enumerate(lines):
        s=ln.strip()
        nm=re.match(r'namespace\s+([A-Za-z0-9_\'\.]+)',s)
        if nm: ns_stack.append(nm.group(1)); continue
        if re.match(r'end\s+([A-Za-z0-9_\'\.]+)',s):
            if ns_stack: ns_stack.pop()
            continue
        if s=='end':
            if ns_stack: ns_stack.pop()
            continue
    return ns_stack
# simpler: for each known lean_name, search for its last segment as decl and verify namespace by prefix match
def find_body(lean_name):
    seg=lean_name.split('.')[-1]
    cands=decl_sites.get(seg,[])
    best=None
    for f,pos,end in cands:
        # verify the namespace prefix appears via namespace decls before pos OR name written fully
        txt=file_txt[f]
        # reconstruct namespace at pos
        prefix=txt[:pos]
        ns=[]
        for m in re.finditer(r'^\s*(namespace\s+([\w\.]+)|end\s+([\w\.]+)|end\s*$)',prefix,re.M):
            if m.group(2): ns.append(m.group(2))
            else:
                if ns: ns.pop()
        full='.'.join(ns+[seg])
        if full==lean_name:
            return f,pos,end
        if best is None: best=(f,pos,end)
    # fallback: maybe decl written with full name
    return best
for ln in lean2label:
    fb=find_body(ln)
    if fb: decl_sites['__FULL__'+ln]=fb

# 3. For each block decl, compute referenced project lean_names in its body
allnames=set(lean2label.keys())
# precompute short->fulls
short2full=defaultdict(list)
for ln in allnames: short2full[ln.split('.')[-1]].append(ln)
edges=defaultdict(set)  # consumer_label -> set(dep_label) by lean reference
for label,d in blocks.items():
    ln=d['lean']
    if not ln: continue
    fb=decl_sites.get('__FULL__'+ln)
    if not fb: continue
    f,pos,end=fb
    body=file_txt[f][pos:end]
    # strip the signature's own name occurrence minimal; find referenced names
    for short,fulls in short2full.items():
        if re.search(r'(?<![A-Za-z0-9_\.])'+re.escape(short)+r'(?![A-Za-z0-9_\'])',body):
            for full in fulls:
                if full==ln: continue
                dep_label=lean2label[full]
                if dep_label!=label:
                    edges[label].add(dep_label)
json.dump({'blocks':{l:{'file':d['file'],'lean':d['lean'],'stmt_uses':sorted(d['stmt_uses'])} for l,d in blocks.items()},
           'lean_edges':{l:sorted(v) for l,v in edges.items()},
           'located':sorted([ln for ln in lean2label if '__FULL__'+ln in decl_sites])},
          open('/tmp/graph.json','w'))
print('blocks',len(blocks),'with lean',sum(1 for d in blocks.values() if d['lean']),'located',sum(1 for ln in lean2label if '__FULL__'+ln in decl_sites))
